from flask import redirect, url_for

def login_redirect(user):
    """
    Redirects the user to their intended destination after authentication.

    Args:
        user: The authenticated user object.

    Returns:
        A redirect response to the user's destination.
    """

    # Get the user's intended destination from their session or database.
    destination = user.session.get('destination') or user.default_destination

    # Redirect the user to their destination.
    return redirect(url_for(destination))